const f = msg.payload;
const fields = {};
for (const [name, r] of Object.entries(f.readings || {})) {
  fields[name] = r.v;
}
fields.seq = f.seq;
msg.payload = [fields, { device_id: f.device_id, domain: f.domain }];
msg.measurement = 'telemetry';
return msg;

const a = msg.payload;
// severity as a numeric field for easy thresholding in Grafana
const sev = a.severity === 'critical' ? 2 : (a.severity === 'warning' ? 1 : 0);
msg.payload = [
  { count: 1, severity_level: sev, detail: a.detail || '' },
  { device_id: a.device_id || 'unknown', kind: a.kind || 'unknown', severity: a.severity || 'info' }
];
msg.measurement = 'alerts';
return msg;
